   117→function seededRandom(seed) {
   118→  let s = seed;
   119→  return () => { s = (s * 16807) % 2147483647; return (s - 1) / 2147483646; };
   120→}
   121→
   122→function weightedChoice(items, weights, rng) {
   123→  const total = weights.reduce((a, b) => a + b, 0);
   124→  let r = rng() * total;
   125→  for (let i = 0; i < items.length; i++) { r -= weights[i]; if (r <= 0) return items[i]; }
   126→  return items[items.length - 1];
   127→}
