   135→function generateDefaultPlatforms(seed = 42) {
   136→  world.platforms = [];
   137→  world.nextPlatformId = 1;
   138→  const rng = seededRandom(seed);
   139→  const colors = { static:'#6688cc', moving:'#cc8844', falling:'#cc4444', bouncy:'#44cc88', rotating:'#aa44cc' };
   140→
   141→  addPlatform({ type:'ground', position:[0,-1,0], size:[40,2,40], color:'#4a7c59', material:'standard', isStatic:true });
   142→
   143→  let last = { x:0, y:1, z:0 };
   144→  for (let i = 0; i < 30; i++) {
   145→    last = { x: last.x+(rng()-.5)*8, y: last.y+1.5+rng()*2, z: last.z+(rng()-.5)*8 };
   146→    const types = ['static','moving','falling','bouncy','rotating'];
   147→    const w = [.45,.2,.15,.1,.1];
   148→    const ptype = weightedChoice(types, w, rng);
   149→    const p = { type:ptype, position:[last.x,last.y,last.z], size:[1.5+rng()*3,.4,1.5+rng()*3], color:colors[ptype], material:'standard', isStatic:ptype==='static' };
   150→    if (ptype==='moving')   p.movement = { axis:['x','y','z'][Math.floor(rng()*3)], amplitude:2+rng()*4, speed:.5+rng()*1.5 };
   151→    if (ptype==='falling')  { p.fallDelay=.5+rng(); p.respawnTime=3+rng()*2; }
   152→    if (ptype==='bouncy')   p.bounceForce = 10+rng()*15;
   153→    if (ptype==='rotating') p.rotation = { axis:'y', speed:.5+rng()*2 };
   154→    addPlatform(p);
   155→  }
   156→  addPlatform({ type:'goal', position:[last.x,last.y+2,last.z], size:[4,.5,4], color:'#ffdd44', material:'emissive', isStatic:true });
   157→}
