}

.cc-modal-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 7px; margin-bottom: 18px; }
.cc-modal-field {
  padding: 10px 11px; border-radius: 4px;
  background: rgba(0,0,0,0.35); border: 1px solid var(--border);
