}
.cc-modal-field:hover { border-color: var(--border2); }
.cc-modal-field-label { font-size: 8px; color: var(--muted); text-transform: uppercase; letter-spacing: 1.5px; margin-bottom: 3px; }
.cc-modal-field-val { font-family: var(--font2); font-size: 12px; font-weight: 700; color: var(--text); letter-spacing: 1px; }

.cc-modal-troxt-msg {
  padding: 12px 14px; border-radius: 5px;
  border: 1px solid rgba(155,135,255,0.2);
  background: rgba(155,135,255,0.05);
  font-size: 11px; color: rgba(232,237,245,0.6); line-height: 1.6; letter-spacing: 0.3px;
