/* SPAWN ANIMATION */
.cc-spawn-anim {
  position: fixed; inset: 0; z-index: 300;
  display: flex; flex-direction: column; align-items: center; justify-content: center;
  pointer-events: none; opacity: 0; transition: opacity 0.6s;
  background: radial-gradient(ellipse at center, rgba(0,255,136,0.04) 0%, transparent 70%);
}
.cc-spawn-anim.active { opacity: 1; }
.cc-spawn-rings {
  position: absolute; inset: 0; display: flex; align-items: center; justify-content: center;
}
.cc-spawn-ring {
  position: absolute; border-radius: 50%; border: 2px solid var(--green);
  animation: ringExpand 2s ease-out infinite;
}
.cc-spawn-ring:nth-child(1) { width: 100px; height: 100px; animation-delay: 0s; }
.cc-spawn-ring:nth-child(2) { width: 200px; height: 200px; animation-delay: 0.3s; }
.cc-spawn-ring:nth-child(3) { width: 320px; height: 320px; animation-delay: 0.6s; }
@keyframes ringExpand {
  0%   { transform: scale(0.4); opacity: 0.8; }
  100% { transform: scale(1.8); opacity: 0; }
}
.cc-spawn-text {
  font-family: var(--font3); font-size: 52px; font-weight: 900;
  letter-spacing: 10px; color: var(--green);
  text-shadow: 0 0 40px var(--green), 0 0 80px rgba(0,255,136,0.4);
  text-transform: uppercase; z-index: 1;
  animation: spawnPop 0.5s cubic-bezier(0.4,0,0.2,1);
}
@keyframes spawnPop {
  0% { transform: scale(0.6) translateY(20px); opacity: 0; }
  60% { transform: scale(1.06); }
  100% { transform: scale(1); opacity: 1; }
}
.cc-spawn-sub {
  font-family: var(--font2); font-size: 12px; letter-spacing: 5px; color: rgba(0,255,136,0.65);
  margin-top: 14px; text-transform: uppercase; z-index: 1;
}

