/* ══════════════════════════════════
   ANIMATION PANEL
══════════════════════════════════ */

/* Mode indicator */
.cc-model-indicator {
  display: flex; align-items: center; gap: 8px;
  padding: 7px 10px; border-radius: 4px;
  background: rgba(0,0,0,0.35); border: 1px solid var(--border);
  margin-bottom: 10px;
  font-family: var(--font2); font-size: 10px; font-weight: 700;
  letter-spacing: 1.5px; text-transform: uppercase; color: var(--muted2);
}
.model-dot {
  width: 8px; height: 8px; border-radius: 50%; flex-shrink: 0;
  transition: background 0.3s, box-shadow 0.3s;
}
.model-dot.procedural {
  background: var(--purple);
  box-shadow: 0 0 8px rgba(155,135,255,0.6);
}
.model-dot.glb {
  background: var(--green);
  box-shadow: 0 0 8px rgba(0,255,136,0.6);
  animation: blink 1.5s ease-in-out infinite;
}
.model-dot.loading {
  background: var(--gold);
  box-shadow: 0 0 8px rgba(255,215,0,0.6);
  animation: blink 0.6s ease-in-out infinite;
}

/* Model grid */
.cc-model-grid {
  display: grid; grid-template-columns: 1fr 1fr; gap: 6px; margin-bottom: 8px;
}
.cc-model-btn {
  padding: 10px 6px; border-radius: 5px;
  border: 1px solid var(--border);
  background: linear-gradient(145deg, rgba(255,255,255,0.03), rgba(0,0,0,0.3));
  color: var(--muted); font-family: var(--font2); font-size: 9px;
  font-weight: 700; letter-spacing: 1px; text-transform: uppercase;
  cursor: pointer; transition: all 0.2s; text-align: center;
  display: flex; flex-direction: column; align-items: center; gap: 5px;
}
.cc-model-btn .model-btn-icon { font-size: 20px; transition: transform 0.2s; }
.cc-model-btn:hover { border-color: var(--border2); color: var(--muted2); }
.cc-model-btn:hover .model-btn-icon { transform: scale(1.2); }
.cc-model-btn.active {
  border-color: rgba(0,255,136,0.4); color: var(--green);
  background: linear-gradient(145deg, rgba(0,255,136,0.08), rgba(0,255,136,0.03));
  box-shadow: 0 0 12px rgba(0,255,136,0.08);
}

.cc-model-btn-proc {
  width: 100%; padding: 9px 12px; border-radius: 4px; margin-bottom: 6px;
  border: 1px solid rgba(155,135,255,0.25);
  background: rgba(155,135,255,0.06); color: var(--purple);
  font-family: var(--font2); font-size: 10px; font-weight: 700;
  letter-spacing: 1.5px; text-transform: uppercase;
  cursor: pointer; transition: all 0.2s; text-align: center;
}
.cc-model-btn-proc:hover {
  border-color: rgba(155,135,255,0.5); background: rgba(155,135,255,0.12);
}

/* Anim-only: hidden when no GLB loaded */
.cc-anim-only {
  opacity: 0.35; pointer-events: none; transition: opacity 0.4s;
}
.glb-active .cc-anim-only {
  opacity: 1; pointer-events: all;
}

/* Base action buttons */
.cc-base-anim-btns { display: flex; gap: 6px; margin-bottom: 6px; }
.cc-anim-action-btn {
  flex: 1; padding: 9px 4px; border-radius: 4px;
  border: 1px solid var(--border);
  background: rgba(0,0,0,0.3); color: var(--muted);
  font-family: var(--font2); font-size: 10px; font-weight: 700;
  letter-spacing: 1px; text-transform: uppercase;
  cursor: pointer; transition: all 0.2s; text-align: center;
}
.cc-anim-action-btn:hover { border-color: var(--border2); color: var(--muted2); }
.cc-anim-action-btn.active {
  border-color: rgba(0,212,255,0.5); color: var(--cyan);
  background: rgba(0,212,255,0.08);
  box-shadow: 0 0 12px rgba(0,212,255,0.08);
}

/* Anim info card */
.cc-anim-info {
  margin-top: 14px; padding: 11px 12px; border-radius: 5px;
  border: 1px solid var(--border);
  background: rgba(0,0,0,0.3);
  display: flex; flex-direction: column; gap: 7px;
}
.cc-anim-info-row { display: flex; justify-content: space-between; align-items: center; }
.anim-info-key { font-size: 8px; color: var(--muted); text-transform: uppercase; letter-spacing: 1.5px; }
.anim-info-val { font-family: var(--font2); font-size: 10px; font-weight: 700; color: var(--cyan); letter-spacing: 0.5px; }

/* ── GLB LOADING OVERLAY ── */
.vp-loading {
  position: absolute; inset: 0; z-index: 10;
  display: flex; flex-direction: column;
  align-items: center; justify-content: center; gap: 14px;
  background: rgba(4,8,16,0.88); backdrop-filter: blur(10px);
  opacity: 0; pointer-events: none; transition: opacity 0.3s;
}
.vp-loading.active { opacity: 1; pointer-events: all; }

.vp-loading-ring {
  width: 52px; height: 52px; border-radius: 50%;
  border: 3px solid rgba(0,212,255,0.12);
  border-top-color: var(--cyan);
  border-right-color: var(--purple);
  animation: spinRing 1s linear infinite;
}
@keyframes spinRing { to { transform: rotate(360deg); } }

.vp-loading-text {
  font-family: var(--font2); font-size: 13px; font-weight: 700;
  letter-spacing: 2px; color: var(--cyan); text-transform: uppercase;
}
.vp-loading-sub {
  font-size: 9px; color: var(--muted); letter-spacing: 3px; text-transform: uppercase;
}

/* ── GLB MODE badge in viewport ── */
.vp-glb-badge {
  position: absolute; bottom: 44px; right: 14px;
  font-family: var(--font2); font-size: 9px; font-weight: 700;
  letter-spacing: 2px; text-transform: uppercase;
  padding: 4px 9px; border-radius: 3px;
  border: 1px solid rgba(0,255,136,0.3);
  background: rgba(0,255,136,0.07); color: var(--green);
  z-index: 3; pointer-events: none;
  display: none;
}
.vp-glb-badge.visible { display: block; }

/* SPAWN ANIMATION */

